// Behavioral Level Description
module mux2to1_behavioral(input [3:0] a, b, input sel, output [3:0] y);
 always @(*) begin
 if (sel == 0)
 y = a;
 else
 y = b;
 end
endmodule

// Structural Level Description using gates
module mux2to1_structural(input [3:0] a, b, input sel, output [3:0] y);
 wire [3:0] sel_b, out_and_a, out_and_b;

 // Invert selection signal
 not (sel_b[0], sel[0]);
 not (sel_b[1], sel[0]);
 not (sel_b[2], sel[0]);
 not (sel_b[3], sel[0]);

 // AND gates for selection
 and (out_and_a[0], a[0], sel_b[0]);
 and (out_and_a[1], a[1], sel_b[1]);
 and (out_and_a[2], a[2], sel_b[2]);
 and (out_and_a[3], a[3], sel_b[3]);

 and (out_and_b[0], b[0], sel[0]);
 and (out_and_b[1], b[1], sel[0]);
 and (out_and_b[2], b[2], sel[0]);
 and (out_and_b[3], b[3], sel[0]);

 // OR gates to combine
 or (y[0], out_and_a[0], out_and_b[0]);
 or (y[1], out_and_a[1], out_and_b[1]);
 or (y[2], out_and_a[2], out_and_b[2]);
 or (y[3], out_and_a[3], out_and_b[3]);
endmodule

library IEEE;
use IEEE.STD_LOGIC_1164.ALL;

entity simple_register is
 Port ( d : in STD_LOGIC_VECTOR (7 downto 0);
 clk : in STD_LOGIC;
 rst : in STD_LOGIC;
 q : out STD_LOGIC_VECTOR (7 downto 0));
end simple_register;

architecture behavioral of simple_register is
begin
 process(clk, rst)
 begin
 if rst = '1' then
 q <= (others => '0'); -- Asynchronous reset
 elsif rising_edge(clk) then
 q <= d; -- Register loads on clock rising edge
 end if;
 end process;
end behavioral;

PROCEDURE digital_design_flow(specifications):
 // Step 1: Analyze requirements
 functional_spec ← analyze_requirements(specifications)

 // Step 2: High-level architecture design
 architecture ← define_architecture(functional_spec)
 blocks ← partition_system(architecture)

 // Step 3: RTL Design
 rtl_description ← describe_behavioral(blocks)

 // Step 4: Synthesis
 gate_level_netlist ← synthesize(rtl_description)
 optimized_netlist ← optimize_for_ppa(gate_level_netlist)

 // Step 5: Verification
 verification_results ← simulate(optimized_netlist)
 IF verification_results FAIL THEN
 RETURN TO Step 3 (redesign)
 END IF

 // Step 6: Physical Design
 layout ← place_and_route(optimized_netlist)

 // Step 7: Timing Analysis
 timing_closure ← analyze_timing(layout)
 IF NOT timing_closure THEN
 RETURN TO Step 4 (re-synthesis)
 END IF

 // Step 8: Fabrication
 chip ← fabricate(layout)

 RETURN chip

